import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import FormBuilder from "../components/FormBuilder";
import FormPreview from "../components/FormPreview";
import { getFormById } from "../services/api";

const FormPage = ({ mode }) => {
  // mode: "create" | "edit" | "preview"
  const { id } = useParams();
  const navigate = useNavigate();
  const [form, setForm] = useState(null);
  const [loading, setLoading] = useState(mode !== "create");
  const [activeTab, setActiveTab] = useState("builder");

  useEffect(() => {
    if (mode !== "create" && id) {
      const fetchForm = async () => {
        try {
          const res = await getFormById(id);
          setForm(res.data.data);
        } catch (error) {
          alert("Form not found.");
          navigate("/");
        } finally {
          setLoading(false);
        }
      };
      fetchForm();
    }
  }, [id, mode, navigate]);

  const handleSave = (savedForm) => {
    setForm(savedForm);
  };

  if (loading) return <div className="loading">Loading form...</div>;

  return (
    <div className="form-page">
      <div className="form-page-header">
        <button className="btn-back" onClick={() => navigate("/")}>
          ← Back to Forms
        </button>
        <h2>
          {mode === "create" ? "Create New Form" : mode === "edit" ? "Edit Form" : "Preview Form"}
        </h2>

        {mode !== "preview" && (
          <div className="tab-switcher">
            <button
              className={activeTab === "builder" ? "tab active" : "tab"}
              onClick={() => setActiveTab("builder")}
            >
              🔧 Builder
            </button>
            <button
              className={activeTab === "preview" ? "tab active" : "tab"}
              onClick={() => setActiveTab("preview")}
            >
              👁 Preview
            </button>
          </div>
        )}
      </div>

      {mode === "preview" ? (
        <FormPreview form={form} />
      ) : activeTab === "builder" ? (
        <FormBuilder existingForm={form} onSave={handleSave} />
      ) : (
        <FormPreview form={form || { title: "Form Preview", description: "", fields: [] }} />
      )}
    </div>
  );
};

export default FormPage;
